#include <bits/stdc++.h>
using namespace std;

int main(){
	double n;
	char a[1000],b[1000];
	cin>>n;
	cin>>a;
	cin>>b;
	int len=strlen(a);
	int q=0;
	for(int i=0;i<len;i++){
		if(a[i]==b[i]){
			q++;
		}
	}
	double ans=1.0*q/len;
	if(ans<n){
		cout<<"no";
	}else{
		cout<<"yes";
	}
	return 0;
}
